      const parts = {x: 0, y: 1, blur: 2, color: "#000000", opacity: 85};
      const rgba = value.match(/rgba?\s*\(\s*([0-9.]+)\s*,\s*([0-9.]+)\s*,\s*([0-9.]+)(?:\s*,\s*([0-9.]+)\s*)?\)/i);
      if (rgba) {
        parts.color = parentHexFromRgb(rgba[1], rgba[2], rgba[3]);
        parts.opacity = parentClampShadowNumber((rgba[4] == null ? 1 : Number(rgba[4])) * 100, 0, 100, 85);
      } else {
        const hex = value.match(/#[0-9a-fA-F]{6}/);
        if (hex) parts.color = String(hex[0]).toLowerCase();
      }
      const numeric = value.replace(/rgba?\s*\([^)]*\)/ig, " ").replace(/#[0-9a-fA-F]{3,6}/g, " ").match(/-?\d+(?:\.\d+)?/g) || [];
      if (numeric.length >= 1) parts.x = parentClampShadowNumber(numeric[0], -12, 12, parts.x, 2);
      if (numeric.length >= 2) parts.y = parentClampShadowNumber(numeric[1], -12, 12, parts.y, 2);
