      const currentFamily = String(data.fontFamily || "");
      const currentTextColor = /^#[0-9a-fA-F]{6}$/.test(String(data.textColor || "")) ? String(data.textColor).toLowerCase() : "#ffffff";
      const currentUiTextColor = /^#[0-9a-fA-F]{6}$/.test(String(data.uiTextColor || "")) ? String(data.uiTextColor).toLowerCase() : "#ffffff";
